class Solution:
    def minSum(self, nums1: List[int], nums2: List[int]) -> int:
        sum1 = sum(nums1)
        sum2 = sum(nums2)
        zeros1 = nums1.count(0)
        zeros2 = nums2.count(0)

        # If both arrays have no zeros, check if sums are equal
        if zeros1 == 0 and zeros2 == 0:
            return sum1 if sum1 == sum2 else -1

        # If one array has no zeros, the other must have sum >= its sum
        if zeros1 == 0:
            if sum1 < sum2:
                return -1
            # We need to replace zeros in nums2 with at least 1 each
            required = sum1 - sum2 + zeros2
            if required < 0:
                return -1
            return sum1
        if zeros2 == 0:
            if sum2 < sum1:
                return -1
            required = sum2 - sum1 + zeros1
            if required < 0:
                return -1
            return sum2

        # Both arrays have zeros
        # We can replace zeros with 1s to minimize the sum
        min_sum1 = sum1 + zeros1
        min_sum2 = sum2 + zeros2

        if min_sum1 == min_sum2:
            return min_sum1
        elif min_sum1 < min_sum2:
            # Need to increase sum1 by at least (min_sum2 - min_sum1)
            # We can do this by increasing the zeros in nums1
            return min_sum2
        else:
            return min_sum1
